local G = DYCLegendary local require = G.DYCModRequire local spells = require( "dyc_spells" ) local GetEntSize = G.GetEntSize local GetEntHitHeight = G.GetEntHitHeight local TableContains = G.lib.TableContains local TableAdd = G.lib.TableAdd local TableRemoveValue = G.lib.TableRemoveValue local CommonFns = require( "dyc_commonfns" ) local IsAliveOrNoHealth = CommonFns.IsAliveOrNoHealth local IsAlive = CommonFns.IsAlive local IsDead = CommonFns.IsDead local IsAAllyToB = CommonFns.IsAAllyToB local CanHit = CommonFns.CanHit local Freeze = CommonFns.Freeze local Ignite = CommonFns.Ignite local CanPoison = CommonFns.CanPoison local Poison = CommonFns.Poison local CurePoison = CommonFns.CurePoison local ReduceSanity = CommonFns.ReduceSanity local HolyDamage = CommonFns.HolyDamage local Attack = CommonFns.Attack local Heal = CommonFns.Heal local CreateDummy = CommonFns.CreateDummy local AddLightChild = CommonFns.AddLightChild local Round = function(num) return math.floor(num + 0.5) end local Clamp = function(num, min, max) return math.min(math.max(num, min), max) end local function IsNumber(o) return o ~= nil and type(o) == "number" end local function IsPosNumber(o) return IsNumber(o) and o > 0x0 end local function IsNonNegNumber(o) return IsNumber(o) and o >= 0x0 end local function IsNegNumber(o) return IsNumber(o) and o < 0x0 end local function IsNonZeroNumber(o) return IsNumber(o) and o ~= 0x0 end local function IsString(o) return o ~= nil and type(o) == "string" end local function IsTable(o) return o ~= nil and type(o) == "table" end local function IsFunction(o) return o ~= nil and type(o) == "function" end local function IsNonEmptyString(o) return IsString(o) and #o > 0x0 end local function ConcatStrings(spl, ...) local tbl = {...} if IsTable(tbl[0x1]) then tbl = tbl[0x1] end local result = "" local count = 0x0 for k, v in pairs(tbl) do if IsNonEmptyString(v) or IsNumber(v) then count = count + 0x1 result = result..(count > 0x1 and spl or "" )..v end end return result end local function GetString(key, default) return G.localization:GetString(key, default) end local function GetNumberString(value) return ""..(math.abs(value) >= 0x14 and Round(value) or Round(value * 0xa) / 0xa) end local function GetPercentString(value) return(math.abs(value) >= 0.2 and Round(value * 0x64) or Round(value * 0x3e8) / 0xa).."%" end local Enchantment = Class(function(self, data) data = data or {} self.name = data.name or "enchantment" self.priority = data.priority or 0x0 self.grade = data.grade or 0x0 self.nameKey = data.nameKey or nil self.desKey = data.desKey or nil self.desColor = data.desColor or nil self.tags = {} if data.tags then for k, v in pairs(data.tags) do self:AddTag(v) end end self.isHidden = data.isHidden or false self.requiredComponents = data.requiredComponents or nil self.bannedPrefabs = data.bannedPrefabs or nil self.requirePositiveDamage = data.requirePositiveDamage or false self.requirePositiveSpeed = data.requirePositiveSpeed or false self.nameFn = data.nameFn or nil self.desFn = data.desFn or nil self.longDesFn = data.longDesFn or nil self.attackFn = data.attackFn or nil self.attackedFn = data.attackedFn or nil self.preDamageFn = data.preDamageFn or nil self.preDamagedFn = data.preDamagedFn or nil self.damageFn = data.damageFn or nil self.damagedFn = data.damagedFn or nil self.targetFn = data.targetFn or nil self.castFn = data.castFn or nil self.timePhaseChangeFn = data.timePhaseChangeFn or nil self.canAddFn = data.canAddFn or nil self.addFn = data.addFn or nil self.removeFn = data.removeFn or nil self.equipFn = data.equipFn or nil self.unequipFn = data.unequipFn or nil self.bonuses = {} if data.bonuses then for k, v in pairs(data.bonuses) do self:SetBonus(k, v) end end self.custom = data.custom or {} end) function Enchantment:__tostring() return string.format( "ENC:%s(%s)" , self.name or "noname" , self:GetDisplayName() or "?" ) end function Enchantment:GetDisplayName(obj) return self.nameFn and (self.nameFn(self, obj) or "" ) or GetString( "enc_name_"..(self.nameKey or self.name)) end function Enchantment:GetDescription(obj) return self.desFn and (self.desFn(self, obj) or "" ) or GetString( "enc_des_"..(self.desKey or self.name)) end function Enchantment:GetLongDescription(obj) return self.longDesFn and (self.longDesFn(self, obj) or "" ) or (G.localization:HasString( "enc_longdes_"..(self.desKey or self.name)) and GetString( "enc_longdes_"..(self.desKey or self.name))) end function Enchantment:HasTag(tag) return self.tags[string.lower(tag)] == true end function Enchantment:AddTag(tag) self.tags[string.lower(tag)] = true end function Enchantment:RemoveTag(tag) self.tags[string.lower(tag)] = nil end function Enchantment:CanAdd(obj) local b = true if self.requiredComponents then b = false for k, v in pairs(self.requiredComponents) do local c = obj and obj.components and obj.components[v] if c then b = true break end end end if self.bannedPrefabs then for k, v in pairs(self.bannedPrefabs) do if obj and obj.prefab and obj.prefab == v then b = false break end end end if self.requirePositiveDamage then local combat = obj.components and obj.components.combat if combat and (not combat.defaultdamage or combat.defaultdamage <= 0x0) then b = false end end if self.requirePositiveSpeed then local locomotor = obj.components and obj.components.locomotor if locomotor and (not locomotor.runspeed or locomotor.runspeed <= 0x0) then b = false end end if self.canAddFn then return b and self.canAddFn(self, obj) end return b end function Enchantment:OnAdd(obj) if self.addFn then self.addFn(self, obj) end end function Enchantment:OnRemove(obj) if self.removeFn then self.removeFn(self, obj) end end function Enchantment:OnEquip(obj, owner, slot) if self.equipFn then self.equipFn(self, obj, owner, slot) end end function Enchantment:OnUnequip(obj, owner, slot) if self.unequipFn then self.unequipFn(self, obj, owner, slot) end end function Enchantment:GetBonus(bonus, obj) if obj and self.bonuses[bonus] then local q = obj:GetQuality() return q * self.bonuses[bonus] end return self.bonuses[bonus] or 0x0 end function Enchantment:SetBonus(bonus, value) self.bonuses[bonus] = value end local function SpawnMeteor(pos) local x, y, z = pos:Get() local firerain = SpawnPrefab( "firerain" ) if firerain then firerain.Transform:SetPosition(x, y, z) firerain:StartStep() end end local function StealSanity(attacker, target, value) value = value or 0x1 local sanity1 = attacker.components.sanity if sanity1 then sanity1:DoDelta(value, true) end local sanity2 = target.components.sanity if sanity2 then sanity2:DoDelta( - value) end end local function StealHealth(attacker, target, value) value = value or 0x1 local health1 = attacker.components.health if health1 then health1:DoDelta(value, true) end local health2 = target.components.health if health2 then health2:DoDelta( - value, false, attacker and attacker.prefab or "NIL" ) end end local function StartHealthAuraTask(inst, isHeal, radius, interval, value, percent) if not IsAlive(inst) then return end local task = inst:DoPeriodicTask(interval, function() if not IsAlive(inst) then return end local p = inst:GetPosition() local noTags = { "FX" , "NOCLICK" , "DECOR" , "INLIMBO" } local ents = TheSim:FindEntities(p.x, p.y, p.z, radius, nil, noTags) for _, ent in pairs(ents) do local follower = ent.components.follower local health = ent.components.health if health and IsAlive(ent) and isHeal and IsAAllyToB(ent, inst) then health:DoDelta(value or (health.GetMax and health:GetMax() or health:GetMaxHealth()) * percent, true) elseif health and IsAlive(ent) and not isHeal and not IsAAllyToB(ent, inst) then health:DoDelta(value and - value or - (health.GetMax and health:GetMax() or health:GetMaxHealth()) * percent, false, inst.prefab or "NIL" ) end end end) return task end local function DurabilityRegen(obj, r, p) local finiteuses = obj.components.finiteuses local perishable = obj.components.perishable local fueled = obj.components.fueled local armor = obj.components.armor if finiteuses then finiteuses:SetUses(math.min(finiteuses.current + (r or finiteuses.total * p), finiteuses.total)) end if perishable then local current = perishable.perishremainingtime local total = perishable.perishtime perishable.perishremainingtime = math.min(current + (r or total * p), total) perishable.inst:PushEvent( "perishchange" , {percent = perishable:GetPercent()}) end if fueled then local total = fueled.maxfuel fueled:DoDelta(r or total * p) end if armor then local current = armor.condition local total = armor.maxcondition armor:SetCondition(math.min(current + (r or total * p), total)) end end local function SetUpTurret(inst, turret, damage, number, interval, cd, key) inst[key.."Count"] = 0x0 inst[key.."Cd"] = 0x0 inst[key.."Task"] = inst:DoPeriodicTask(interval, function() if inst[key.."Cd"] > 0x0 then inst[key.."Cd"] = inst[key.."Cd"] - interval return end if not IsAlive(inst) then return end local combat = inst.components.combat local target = combat and combat.target if not target or type(target) ~= "table" or not target.IsValid then return end local expRadius = 0x3 local targetSpeed = target.Physics and Vector3(target.Physics:GetVelocity()):Length() or 0x0 local projSpeed = math.max(0xf, targetSpeed + 0xa) local rot = - target:GetRotation() local p = target:GetPosition() local pos = inst:GetPosition() local dist = math.sqrt(math.pow(p.x - pos.x, 0x2) + math.pow(p.z - pos.z, 0x2)) local radius1 = inst.Physics and inst.Physics:GetRadius() or 0x0 local radius2 = target.Physics and target.Physics:GetRadius() or 0x0 if dist + radius1 + radius2 > 0x1e then return end local targetMove = targetSpeed * dist / (projSpeed - targetSpeed) local pSuggested = Vector3(p.x + targetMove * math.cos(rot / 0xb4 * math.pi), 0x0, p.z + targetMove * math.sin(rot / 0xb4 * math.pi)) p = pSuggested if not IsAAllyToB(inst, GetPlayer()) then SpawnPrefab( "dyc_fx_aoering" ):SetAlertRing(math.max(dist / (projSpeed - targetSpeed), 0.1), 0.4):SetRadius(expRadius).Transform:SetPosition(p:Get()) end local pf, expPf = "" , "" if turret == "fireball" and inst.SoundEmitter then inst.SoundEmitter:PlaySound( "dontstarve/wilson/fireball_explo" ) pf = "dyc_projectile_fireball" expPf = "dyc_fx_explode_large" elseif turret == "iceball" then pf = "dyc_projectile_iceball" expPf = "dyc_fx_explode_blue_large" end local proj = SpawnPrefab(pf) proj.Transform:SetPosition(pos:Get()) local projectile = proj.components.projectile projectile:SetSpeed(projSpeed) projectile:SetBezier(1.5) projectile:SetLaunchOffset({x = 0.8, y = GetEntHitHeight(inst)}) projectile:Throw(inst, p, inst) projectile:SetOnHitFn(function(proj, attacker, target, weapon) local isOnWater = proj.GetIsOnWater and proj:GetIsOnWater() if not isOnWater then local fxGround = SpawnPrefab( "dyc_fx_burntground_large" ) fxGround.Transform:SetPosition(p.x, 0x0, p.z) fxGround.Transform:SetRotation(math.random() * 0x168) end local expo = SpawnPrefab(expPf) expo.Transform:SetPosition(p.x, 0x0, p.z) local ents = TheSim:FindEntities(p.x, p.y, p.z, expRadius) for k, v in pairs(ents) do if CanHit(v, attacker) then if turret == "fireball" then if IsAlive(v) and v.components.health then v.isNonAttDmg = true v.components.health:DoFireDamage(damage, attacker, true) v.isNonAttDmg = nil end elseif turret == "iceball" then if IsAlive(v) and v.components.combat then v.isNonAttDmg = true v.components.combat:GetAttacked(attacker, damage, nil) v.isNonAttDmg = nil end if IsAlive(v) then Freeze(v) end end if IsAliveOrNoHealth(v) and v.components.workable and v.components.workable.workleft > 0x0 then v.components.workable:WorkedBy(attacker, 0x1) end end end proj:Remove() end) inst[key.."Count"] = inst[key.."Count"] + 0x1 if inst[key.."Count"] >= number then inst[key.."Count"] = 0x0 inst[key.."Cd"] = cd end end) end local function CreateFrostZoneTask(inst, radius, duration, cooldown, buff) local cd = 0x0 return inst:DoPeriodicTask(FRAMES, function() if cd > 0x0 then cd = cd - FRAMES return end if not IsAlive(inst) then return end local combat = inst.components.combat local target = combat and combat.target if not target or type(target) ~= "table" or not target.IsValid then return end local dummy = CreateDummy() local pos = target:GetPosition() dummy.Transform:SetPosition(pos:Get()) AddLightChild(dummy, 0.4, 0.7, 0x1) local fx1 = SpawnPrefab( "dyc_p_frost_area" ) fx1.Transform:SetPosition(pos:Get()) fx1:SetPercentage(radius / 0x3) local fx2 = SpawnPrefab( "dyc_p_frost_area_snowflake" ) fx2.Transform:SetPosition(pos:Get()) fx2:SetPercentage(radius / 0x3) local timer, timer2 = 0x0, 0x0 if not IsAAllyToB(inst, GetPlayer()) then SpawnPrefab( "dyc_fx_aoering" ):SetAlertRing(duration, duration - 0.5):SetColor(0x1, 0x0, 0x0, 0.5):SetRadius(radius).Transform:SetPosition(pos:Get()) end dummy:DoPeriodicTask(FRAMES, function() timer = timer + FRAMES timer2 = timer2 + FRAMES if timer >= duration then dummy:Remove() fx1:Remove() fx2:Remove() return end if timer2 > 0.15 and IsAlive(inst) then timer2 = 0x0 local ents = TheSim:FindEntities(pos.x, pos.y, pos.z, radius) for k, ent in pairs(ents) do if CanHit(ent, inst) and IsAlive(ent) then ent:AddBuff(buff, inst) local temperature = ent.components.temperature local current = temperature and temperature.current if temperature and current and current > - 0xa and temperature.DeltaTemp then temperature:DeltaTemp( - 0xa) end end end end end) cd = cooldown end) end local function StartCooldown(inst, cd, key) key = key or "dycPasSkillCd" inst[key] = cd local task = nil task = inst:DoPeriodicTask(FRAMES, function() inst[key] = inst[key] - FRAMES if inst[key] <= 0x0 then inst[key] = 0x0 task:Cancel() end local percent = Clamp(0x1 - inst[key] / cd, 0x0, 0x1) inst:PushEvent( "cooldownchange" , {percent = percent}) end) end local function IsInCooldown(inst, key) key = key or "dycPasSkillCd" return inst[key] and inst[key] > 0x0 end local function IsNotUsedUp(item) local finiteuses = item and item.components.finiteuses return not finiteuses or finiteuses:GetUses() > 0x0 end local function Disarm(target, attacker) local inv = target and target.components.inventory if inv then local item = inv:GetEquippedItem(EQUIPSLOTS.HANDS) if not item then return end inv:DropItem(item) if item.Physics then local x, y, z = item:GetPosition():Get() y = 0.1 item.Physics:Teleport(x, y, z) local p2 = target:GetPosition() local p1 = attacker:GetPosition() local vel = (p2 - p1):GetNormalized() local speed = 0x5 + (math.random() * 0x2) local angle = math.atan2(vel.z, vel.x) + math.rad(math.random() * 0x14 - 0xa) item.Physics:SetVel(math.cos(angle) * speed, 0xa, math.sin(angle) * speed) end end end local function AddFx(target, prefab, sz, h0) sz = sz or 0x1 h0 = h0 or 0x0 local fx = SpawnPrefab(prefab) if fx then local w, h = GetEntSize(target) local size = math.min(w, h) * sz target:AddChild(fx) fx.Transform:SetPosition(0x0, h * h0, 0x0) fx.Transform:SetScale(size, size, size) end return fx end local function AddShadowShieldFX(inst, duration) inst.hasShadowShieldFX = true local fx = AddFx(inst, "dyc_fx_shadowshield" , 0.8, 0.2) fx.AnimState:SetDeltaTimeMultiplier(1.5) fx.SoundEmitter:PlaySound( "dontstarve/impacts/impact_forcefield_armour_dull" ) fx.AnimState:PlayAnimation( "hit" ) fx.AnimState:PushAnimation( "idle_loop" ) inst:DoTaskInTime(duration or 0x2, function() fx:kill_fx() inst.hasShadowShieldFX = false end) end local function E_AttackSpeed(g, p) return Enchantment({ nameKey = "attackspeed" , grade = g, tags = { "attackspeed_percent" }, requiredComponents = { "weapon" , "combat" ,}, requirePositiveDamage = true, bonuses = {attackspeed_percent = p,}, nameFn = function(self) return GetString( "enc_name_"..self.nameKey).."("..GetPercentString(self:GetBonus( "attackspeed_percent" ))..")" end, desFn = function(self, obj) local value = self:GetBonus( "attackspeed_percent" , obj) or 0x0 local str = GetPercentString(value) return string.format(GetString( "enc_des_attackspeed" ), str) end,}) end local function E_Speed(g, v) return Enchantment({nameKey = "speed" , grade = g, tags = { "speed" }, requiredComponents = { "locomotor" , "equippable" ,}, bannedPrefabs = { "kraken" }, requirePositiveSpeed = true, bonuses = {speed = v,}, canAddFn = function(self, obj) return #obj:GetEnchantmentsWithTag( "speed_percent" ) <= 0x0 and #obj:GetEnchantmentsWithTag( "speed" ) <= 0x0 end, nameFn = function(self) return GetString( "enc_name_"..self.nameKey).."("..GetNumberString(self:GetBonus( "speed" ))..")" end, desFn = function(self, obj) local value = self:GetBonus( "speed" , obj) or 0x0 local str = GetNumberString(value) return string.format(GetString( "enc_des_speed" ), str) end,}) end local function E_SpeedPercent(g, p) return Enchantment({nameKey = "speed" , grade = g, tags = { "speed_percent" }, requiredComponents = { "locomotor" , "equippable" ,}, bannedPrefabs = { "kraken" }, requirePositiveSpeed = true, bonuses = {speed_percent = p,}, canAddFn = function(self, obj) return #obj:GetEnchantmentsWithTag( "speed_percent" ) <= 0x0 and #obj:GetEnchantmentsWithTag( "speed" ) <= 0x0 end, nameFn = function(self) return GetString( "enc_name_"..self.nameKey).."("..GetPercentString(self:GetBonus( "speed_percent" ))..")" end, desFn = function(self, obj) local value = self:GetBonus( "speed_percent" , obj) or 0x0 local str = GetPercentString(value) return string.format(GetString( "enc_des_speed" ), str) end,}) end local function E_Damage(g, dmg) return Enchantment({nameKey = "attack" , grade = g, tags = { "damage" }, requiredComponents = { "weapon" , "combat" ,}, requirePositiveDamage = true, bonuses = {damage = dmg,}, nameFn = function(self) return GetString( "enc_name_"..self.nameKey).."("..GetNumberString(self:GetBonus( "damage" ))..")" end, desFn = function(self, obj) local value = self:GetBonus( "damage" , obj) or 0x0 local str = GetNumberString(value) return string.format(GetString( "enc_des_attack" ), str) end,}) end local function E_DamagePercent(g, p) return Enchantment({nameKey = "attack" , grade = g, tags = { 